#include <regex>
#include <string>

std::string convertMarkdownToHtml(const std::string& markdown) {
    std::string html;
    std::regex italicRegex("_(.*?)_");
    std::regex boldRegex("__(.*?)__");
    std::regex linkRegex("\\[(.*?)\\]\\((.*?)\\)");
    std::regex headerRegex("^(#{1,6}.*$");

    html += "<html><body>";
    for (std::string line : split(markdown, "\n")) {
        if (std::regex_match(line, italicRegex)) {
            html += "<i>" + std::regex_replace(line, italicRegex, "$1") + "</i><br>";
        } else if (std::regex_match(line, boldRegex)) {
            html += "<b>" + std::regex_replace(line, boldRegex, "$1") + "</b><br>";
        } else if (std::regex_match(line, linkRegex)) {
            std::string linkText = std::regex_replace(line, linkRegex, "$1");
            std::string linkUrl = std::regex_replace(line, linkRegex, "$2");
            html += "<a href=\"" + linkUrl + "\">" + linkText + "</a><br>";
        } else if (std::regex_match(line, headerRegex)) {
            std::string headerText = std::regex_replace(line, headerRegex, "$0");
            int level = std::stoi(std::regex_replace(std::regex_replace(headerText, headerRegex, ""), "^#", ""));
            html += "<h" + std::to_string(level) + ">" + std::regex_replace(headerText, headerRegex, "$0") + "</h" + std::to_string(level) + "><br>";
        } else {
            html += line + "<br>";
        }
    }
    html += "</body></html>";

    return html;
}

std::vector<std::string> split(const std::string& str, char delimiter) {
    std::vector<std::string> tokens;
    size_t start = 0;
    size_t end = str.find(delimiter);
    while (end!= std::string::npos) {
        tokens.push_back(str.substr(start, end - start));
        start = end + 1;
        end = str.find(delimiter, start);
    }
    tokens.push_back(str.substr(start));
    return tokens;
}
```

